commands.cmd:
base=/sys/devices/system/cpu/cpu0/cpufreq
gov=$(cat "$base/scaling_governor") || { echo "scaling_governor unreadable" >&2; exit 1; }
cur=$(cat "$base/scaling_cur_freq") || { echo "scaling_cur_freq unreadable" >&2; exit 1; }
maxf=$(cat "$base/cpuinfo_max_freq") || { echo "cpuinfo_max_freq unreadable" >&2; exit 1; }
printf '%s\n%s\n%s\n' "$gov" "$cur" "$maxf" | awk '
  NR==1{g=$1} NR==2{c=$1} NR==3{m=$1}
  END{
    if (g=="" || m=="") { print "cpufreq fields missing" > "/dev/stderr"; exit 1 }
    printf "{\"governor\":\"%s\",\"cur_freq_khz\":%d,\"max_freq_khz\":%d,\"freq_pct\":\"%.1f\"}",
      g, c, m, (m>0 ? c/m*100 : 0)
  }' || exit 1
